import React from 'react';
import { Link } from 'react-router-dom';

function MainMenu() {
  return (
    <div style={styles.container}>
      <h1 style={styles.title}>YallaShoot</h1>
      <nav style={styles.menu}>
        <Link to="/start-game" style={styles.button}>Start Game</Link>
        <Link to="/create-game" style={styles.button}>Create Game</Link>
        <Link to="/set-game" style={styles.button}>Set Game</Link>
        <Link to="/players" style={styles.button}>Players Setting</Link>
        <Link to="/history" style={styles.button}>History</Link>
      </nav>
    </div>
  );
}

const styles = {
  container: {
    backgroundColor: '#D6F8D6',  // Nyanza background
    minHeight: '100vh',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    fontFamily: "'Press Start 2P', cursive",  // Old-school font
  },
  title: {
    fontSize: '36px',
    marginBottom: '40px',
    color: '#293F14',  // Pakistan Green
    textShadow: '2px 2px #7FC6A4',  // Cambridge Blue shadow effect
  },
  menu: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
    width: '250px',
  },
  button: {
    backgroundColor: '#386C0B',  // Office Green
    color: '#FFFFFF',
    padding: '15px',
    borderRadius: '10px',  // Slight curve for retro style
    textAlign: 'center',
    textDecoration: 'none',
    fontSize: '14px',
    border: '2px solid #5D737E',  // Payne's Gray border
    boxShadow: '3px 3px #7FC6A4',  // Cambridge Blue shadow
    transition: 'transform 0.2s',
  },
  buttonHover: {
    transform: 'scale(1.05)',
  }
};

export default MainMenu;
